const records = $input.item.json.records || [];
return records.map(r => ({
  json: {
    record_id: r.id,
    business_name: r.fields.business_name || '',
    website: r.fields.website || '',
    domain: r.fields.domain || '',
    phone: r.fields.phone || '',
    address: r.fields.address || '',
    city: r.fields.city || '',
    state: r.fields.state || '',
    google_rating: r.fields.google_rating || null,
    review_count: r.fields.review_count || 0,
    category: r.fields.category || '',
    ai_score: r.fields.ai_score || 0,
    ai_signals: r.fields.ai_signals || '',
    ai_summary: r.fields.ai_summary || ''
  }
}));

const hunterData = $input.item.json.data || {};
const emails = hunterData.emails || [];
const prevRecord = $('Split Into Items').item.json;

if (emails.length === 0) {
  return [{ json: { ...prevRecord, contact_email: null, contact_name: null, hunter_confidence: null } }];
}

const priority = ['owner', 'ceo', 'president', 'manager', 'office', 'admin', 'info', 'contact'];
let bestEmail = null, bestName = null, bestConfidence = null;

for (const keyword of priority) {
  const match = emails.find(e => e.position?.toLowerCase().includes(keyword) || e.type === 'personal');
  if (match) {
    bestEmail = match.value;
    bestName = [match.first_name, match.last_name].filter(Boolean).join(' ') || null;
    bestConfidence = match.confidence || null;
    break;
  }
}

if (!bestEmail && emails.length > 0) {
  bestEmail = emails[0].value;
  bestName = [emails[0].first_name, emails[0].last_name].filter(Boolean).join(' ') || null;
  bestConfidence = emails[0].confidence || null;
}

return [{ json: { ...prevRecord, contact_email: bestEmail, contact_name: bestName, hunter_confidence: bestConfidence } }];

// Apollo errored — pass through with no mobile data
let prevRecord;
try {
  prevRecord = $('Extract Best Email').item.json;
} catch(e) {
  prevRecord = $('Hunter Error — Continue').item.json;
}
return [{ json: { ...prevRecord, mobile_phone: null } }];

const people = ($input.item.json.people || []);

let prevRecord;
try {
  prevRecord = $('Extract Best Email').item.json;
} catch(e) {
  prevRecord = $('Hunter Error — Continue').item.json;
}

if (people.length === 0) {
  return [{ json: { ...prevRecord, mobile_phone: null } }];
}

// Prefer owner > ceo > president, then fall back to first result
const titlePriority = ['owner', 'ceo', 'president'];
let bestPerson = null;
for (const title of titlePriority) {
  const match = people.find(p => p.title?.toLowerCase().includes(title));
  if (match) { bestPerson = match; break; }
}
if (!bestPerson) bestPerson = people[0];

// Extract mobile phone — prefer type 'mobile', fall back to first available
const phoneNumbers = bestPerson.phone_numbers || [];
let mobilePhone = null;
const mobileEntry = phoneNumbers.find(p => p.type === 'mobile');
if (mobileEntry) {
  mobilePhone = mobileEntry.sanitized_number || mobileEntry.raw_number || null;
} else if (phoneNumbers.length > 0) {
  mobilePhone = phoneNumbers[0].sanitized_number || phoneNumbers[0].raw_number || null;
}

// Apollo name takes precedence over Hunter (more authoritative for business owners)
const apolloName = bestPerson.name ||
  [bestPerson.first_name, bestPerson.last_name].filter(Boolean).join(' ') ||
  null;
const contactName = apolloName || prevRecord.contact_name;

return [{ json: { ...prevRecord, mobile_phone: mobilePhone, contact_name: contactName } }];

const error = $input.item.json;

// Only handle 409 conflicts — re-throw everything else
const statusCode = error.statusCode || error.httpStatusCode || 0;
if (statusCode !== 409) {
  const msg = error.message || JSON.stringify(error).slice(0, 300);
  throw new Error(`HubSpot contact creation failed (HTTP ${statusCode}): ${msg}`);
}

let errorBody = error.error;
if (typeof errorBody === 'string') {
  try { errorBody = JSON.parse(errorBody); } catch(e) { errorBody = { message: errorBody }; }
}

const message = errorBody?.message || error.message || '';

let existingId = (message.match(/existing ID:\s*(\d+)/i) || [])[1] || null;
if (!existingId) {
  existingId = errorBody?.context?.id?.[0]
    || errorBody?.identityProfile?.vid?.toString()
    || null;
}

let prevRecord;
try {
  prevRecord = $('Extract Apollo Contact').item.json;
} catch(e) {
  try {
    prevRecord = $('Apollo Error — Continue').item.json;
  } catch(e2) {
    try { prevRecord = $('Extract Best Email').item.json; } catch(e3) {}
    if (!prevRecord) prevRecord = $('Hunter Error — Continue').item.json;
  }
}

if (!existingId) {
  throw new Error(`HubSpot duplicate detected but no existing ID found: ${message}`);
}

return [{ json: { ...prevRecord, hubspot_existing_id: existingId, is_duplicate: true } }];

const item = $input.item.json;

let sourceRecord;
try {
  sourceRecord = $('Extract Apollo Contact').first().json;
} catch(e) {
  try {
    sourceRecord = $('Apollo Error — Continue').first().json;
  } catch(e2) {
    try { sourceRecord = $('Extract Best Email').first().json; } catch(e3) {}
    if (!sourceRecord) sourceRecord = $('Hunter Error — Continue').first().json;
  }
}

let duplicateId = null;
try { duplicateId = $('Handle HubSpot Duplicate').first().json.hubspot_existing_id; } catch(e) {}

const hubspotContactId = item.id || duplicateId || null;

if (!hubspotContactId) {
  throw new Error('HubSpot contact ID not available after create/update.');
}

return [{ json: { ...sourceRecord, hubspot_contact_id: hubspotContactId } }];

const dealId = $input.item.json.id;
const contactRecord = $('Set Contact ID').item.json;
return [{ json: { ...contactRecord, deal_id: dealId, contact_id: contactRecord.hubspot_contact_id } }];

const slackUrl = $env.SLACK_WEBHOOK_URL;
if (!slackUrl) return [{ json: { skipped: true } }];
const r = $('Set Contact ID').item.json;
const msg = `🔧 *New Qualified Lead*
*${r.business_name}* — Score: ${r.ai_score}/10
📍 ${r.city || ''}, ${r.state || ''}
📞 ${r.phone || 'N/A'}${r.mobile_phone ? ' | 📱 ' + r.mobile_phone : ''}
📧 ${r.contact_email || 'No email found'}
🌐 ${r.website || 'N/A'}
*Why they qualify:*
${r.ai_signals || ''}
_${r.ai_summary || ''}_`;
return [{ json: { slackUrl, slackBody: { text: msg } } }];

const slackUrl = $env.SLACK_WEBHOOK_URL;
if (!slackUrl) return [{ json: {} }];
const err = $input.item.json;
return [{ json: { slackUrl, slackBody: { text: `🚨 *Workflow C Error*\n${err.execution?.error?.message || 'Unknown error'}` } } }];
